import { ColumnDef } from "@tanstack/react-table"
import { Link } from "react-router-dom"

export type DataUser = {
    id: number
    first_name: string
    last_name: string
    phone: string
    email: string
    role: string
}

export const columns: ColumnDef<DataUser>[] = [
    {
        accessorKey: "no",
        header: "No",
        cell: (info) => info.row.index + 1
    },
    {
        accessorKey: "first_name",
        header: "First Name",
    },
    {
        accessorKey: "last_name",
        header: "Last Name",
    },
    {
        accessorKey: "phone",
        header: "Phone",
    },
    {
        accessorKey: "email",
        header: "Email",
    },
    {
        accessorKey: "role",
        header: "Role",
    },
    {
        accessorKey: "action",
        header: "Action",
        cell: ({ row }) => {
            return (
                <div className="flex gap-2">
                    <Link to={`/user-management/edit/${row.original.id}`} className="py-0.5 px-2 rounded-sm bg-blue-500 text-white">Edit</Link>
                    <button className="py-0.5 px-2 rounded-sm bg-red-500 text-white">Delete</button>
                </div>
            )
        }
    }
]

